pragma solidity ^0.8.20;

contract Crowdsale {
    uint256 public constant TARGET = 100 ether;

    // Track received funds with internal accounting instead of
    // trusting the raw balance, which anyone can inflate:
    uint256 public totalDeposited;
    mapping(address => uint256) public deposits;

    function deposit() external payable {
        deposits[msg.sender] += msg.value;
        totalDeposited += msg.value;
    }

    function finalize() external {
        // BAD:  require(address(this).balance == TARGET);
        // An attacker can selfdestruct 1 wei into the contract and
        // the equality will never hold again.

        // GOOD: use >= and compare against internal accounting:
        require(totalDeposited >= TARGET, "target not reached");
        // ... finalize sale ...
    }
}
